"""
mkt-context: Job chapters 30–32
Job's lament of social humiliation and fall from honor (ch30),
his comprehensive oath of innocence — the ethical climax of the OT wisdom tradition (ch31),
and the introduction of Elihu, the young disputant who waited for his elders (ch32).
93 verses: ch30 (31), ch31 (40), ch32 (22).
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

JOB_CONTEXT_30_32 = {
  "30": {
    "1": "<p>'But now they laugh at me, men who are younger than I, whose fathers I would have disdained to set with the dogs of my flock.' Chapter 30 is the counter-movement to chapter 29: Job's former honor (ch29) is now replaced by total social humiliation. The reversal is measured by age: the young men who now mock him are men whose fathers Job considered too disreputable to employ as shepherds. In the honor-shame culture of the ancient Near East, age was the primary social hierarchy — younger men owed deference to older men automatically. For young men to mock an elder was a catastrophic violation of the social order. The threshold was extreme: these were not merely poor men but men Job explicitly would not trust with the most menial task in his household economy.</p>",
    "2": "<p>'What could I gain from the strength of their hands, men whose vigor is gone?' The men are described as lacking even physical vigor (<em>kōaḥ yādêhem</em>, strength of their hands), placing them at the bottom of the ancient social hierarchy. In the agricultural and pastoral economy of the ancient world, physical labor was the primary economic contribution of the poor; a man who lacked even this was utterly marginal. Job's former social position was so elevated that he would not have hired these men for the lowest physical work — the contrast with his current position (mocked by them) is the most extreme social reversal imaginable.</p>",
    "3": "<p>'Through want and hard hunger they gnaw the dry ground by night in waste and desolation.' The description of these men as gnawing the dry ground in desolation draws on the ANE image of the landless poor who were forced outside the settled agricultural economy. In the ancient world, the social hierarchy ran from landed nobility → free tenants → hired laborers → the landless poor → slaves → outcasts. The men who now mock Job are described as occupying the extreme bottom of this hierarchy — they survive in the wilderness, outside the economy of the settled land entirely.</p>",
    "4": "<p>'They pick saltwort and the leaves of bushes, and the roots of the broom tree for their food.' Saltwort (<em>mallûaḥ</em>, a salt-tolerant plant of waste ground) and broom tree roots (<em>šōrešê rəṯem</em>) were known as the last resort of the desperately hungry — they are bitter, barely edible plants of the desert. In the ancient world, the type of food a person ate was a direct social indicator: grain-bread was civilized food, wild plants were marginal food, and the plants Job names here represent the absolute bottom of the food hierarchy. These are the desert survivalists, completely outside the covenant community's agricultural economy.</p>",
    "5": "<p>'They are driven out from human company; they shout after them as after a thief.' Being driven from human community (<em>gārěšû min-gaʿ</em>) was the ancient equivalent of total social exclusion — comparable to the proscription of murderers, adulterers, and covenant-breakers in Israelite law. The public shout after them 'as after a thief' reproduces the formal hue-and-cry (<em>zeʿāqāh</em>) which the community raised to catch criminals in the act. These people are not merely poor; they are treated as criminals even when they have done nothing — they are permanently marked as outside legitimate society.</p>",
    "6": "<p>'In the gullies of the torrents they must dwell, in holes of the earth and of the rocks.' The dwelling places of these men — gullies (<em>ʿărôṣ naḥălîm</em>), holes in the earth and rocks — are the habitations of animals, not humans. In the ancient world, the proper human habitat was the city or village: houses built of stone or mud-brick, organized around the communal well and the city gate. Dwelling in holes and gullies was the mark of the utterly dehumanized — Elijah fled to a cave (1 Kgs 19:9), but as a temporary refuge; these people live there permanently by social necessity. The images prepare for Job's ironic reversal: these subhumans are now his social superiors — he has fallen below even them.</p>",
    "7": "<p>'Among the bushes they bray; under the nettles they huddle together.' The braying (<em>yinhăqû</em>) among the bushes compares these people to donkeys — in the ancient world, the comparison of humans to animals was an extreme insult, inverting the hierarchy of Genesis 1:28 where humans were given dominion over animals. The image of huddling together under nettles (stinging plants that no sensible person would choose) captures the complete loss of dignity: they have no shelter but thorns. The donkey-braying image also echoes Job's own use of the donkey metaphor in 6:5 — the animal that cries only when in genuine need.</p>",
    "8": "<p>'A senseless, disreputable brood, they have been whipped out of the land.' The description of them as 'a senseless brood' (<em>bənê-nāḇāl</em>, literally sons of the fool/Nabal — <em>nāḇāl</em> being the same term used for the morally base person who denies God, Ps 14:1; 53:1) and 'disreputable' (<em>bənê-bəlî-šēm</em>, sons without a name — no genealogy, no clan identity) identifies them as permanently marked people without social standing. To have no name (<em>šēm</em>) in the ancient Near East was to have no identity — the social self was constituted by family lineage and clan membership. These are people without that constitutive social identity.</p>",
    "9": "<p>'And now I have become their song; I am a byword to them.' Becoming a song (<em>nəḡînaṯām</em>, their song of mockery) and a byword (<em>millāh</em>, their word/saying) captures the formal social mechanism of shaming in oral culture: songs of mockery (<em>qînāh</em> inverted) and proverbs encoding someone's disgrace were how communities marked and preserved social shame. Lamentations uses the same vocabulary for Jerusalem's humiliation (Lam 3:14: 'I have become the laughingstock of all peoples, the object of their taunts all day long'). In the ancient world, to become the subject of a mocking song meant your shame was perpetually reproduced in community memory.</p>",
    "10": "<p>'They abhor me; they keep aloof from me; they do not hesitate to spit at my face.' Spitting was the most extreme ritual gesture of contempt and rejection in the ancient Near East. In Israelite law, the widow who refused the levirate marriage spat in the face of the man who refused his duty (Deut 25:9); Numbers 12:14 treats being spat at by one's father as the deepest humiliation. The gesture was not merely insulting but socially defining: to be spat at in public was to be formally declared unclean, untouchable, and socially dead. Job, who formerly sat in the honored gate (29:7), is now publicly spat upon by the lowest members of society.</p>",
    "11": "<p>'Because God has loosed my cord and humbled me, they have cast off restraint in my presence.' The 'loosening of the cord' (<em>yitˑr ʾyeṯrô</em>) refers to the restraining cord that kept social deference in place — when the cord is loosed (by divine action), social hierarchy collapses. Job explicitly attributes his social humiliation to divine causation: God has undone the social order that kept him protected. In the honor-shame world, a great man's social protection was the visible sign of divine favor; its removal was immediately interpreted by the community as divine rejection, which licensed the community's own rejection. The collapse of Job's social dignity is both effect and cause of his theological crisis.</p>",
    "12": "<p>'On my right hand the rabble rise; they push away my feet; they cast up against me their ways of destruction.' The description of an organized assault — the <em>pirhāḥ</em> (rabble/youth) rising on his right hand (the position of the legal advocate and the honored guest) and pushing away his feet — uses military and legal imagery simultaneously. In legal proceedings, one's advocate stood at the right hand (Ps 109:31: 'he stands at the right hand of the needy'); the crowd taking the right-hand position means they have displaced his advocate. In military terms, attacking from the right was the standard tactic for attacking the unshielded side. The social humiliation has forensic and military dimensions simultaneously.</p>",
    "13": "<p>'They break up my path; they promote my calamity; they need no one to help them.' The breaking of paths (<em>nāṯəsû nəṯîḇāṯay</em>) is an image of deliberate sabotage — destroying the roads that allow travel and commerce. In the ancient world, roads and paths were maintained by the community and their destruction was an act of war or social sabotage. Job's calamity (<em>hawwāh</em>, ruinous destruction) is 'promoted' (advanced, helped along) by the crowd — they participate enthusiastically in his destruction without being organized or directed. This spontaneous participation in the destruction of the fallen is the social mechanism of the honor-shame world: the formerly honored become fair game for everyone when divine protection is visibly withdrawn.</p>",
    "14": "<p>'As through a wide breach they come; amid the crash they roll on.' The image of a military breach in a city wall (<em>pereṣ</em>, the same word as Perez/breaking-through in Gen 38:29) captures the complete collapse of Job's social defenses. In the ancient world, the siege was the standard military tactic: the enemy would breach the city wall and pour through. The crowd's assault on the now-unprotected Job is analogous to troops flooding through a breached wall — once the defense (divine favor) is removed, there is nothing to slow the assault. The imagery echoes Amos 5:19 and the prophetic descriptions of siege warfare as divine judgment.</p>",
    "15": "<p>'Terrors are turned upon me; my honor is pursued as by the wind, and my prosperity has passed away like a cloud.' The 'terrors' (<em>ballāhôṯ</em>, the same term used in 18:14 for the 'king of terrors' = death) are now 'turned upon' Job in the double sense: turned against him, and turned so that they face him directly. His honor (<em>nəḏîḇāh</em>, noble dignity) is 'pursued as by the wind' — the wind that catches and carries away something weightless and valuable. The cloud metaphor for his prosperity (<em>yəšûʿāh</em>, salvation/prosperity) echoes the cloud images of ch14 (14:2: man comes like a flower and flees like a shadow). The ANE iconographic language of honor and nobility is used to describe their complete dissolution.</p>",
    "16": "<p>'And now my soul is poured out within me; days of affliction have taken hold of me.' The pouring out of the soul (<em>nap̄šî yiššāp̄ēḵ</em>) is the physiological language of complete emotional exhaustion — the same image used in Lam 2:12 (children whose souls are poured out on their mothers' bosoms) and in the phrase 'poured out like water' in Ps 22:14. The 'days of affliction' (<em>yamê-ʿōnî</em>) echo the earlier description of human existence as 'full of trouble' (14:1: <em>śāḇaʿ rōgez</em>). What was a general observation about human existence has become Job's specific experience: he embodies the worst-case scenario of the wisdom tradition's honest anthropology.</p>",
    "17": "<p>'The night racks my bones, and the pain that gnaws me takes no rest.' The night that 'racks' (<em>yiqqār</em>, to be pierced/bored through — from the root of <em>neqeḇ</em>, a hole bored through) the bones is the insomnia of extreme physical pain that prevents the normal recovery of sleep. In the ancient world, night was the time of healing and divine communication (dreams and visions came at night), but for the severely suffering person, night was a prolonged torment. The 'gnawing pain' (<em>ʿōrəqay</em>, those who gnaw me, personified as attackers) uses a verb for the gnawing of animals — Job's pain is animated, predatory, relentless. The physiology of suffering is being described with sociological vocabulary (attackers) and vice versa.</p>",
    "18": "<p>'With great force my garment is disfigured; it binds me about like the collar of my tunic.' The garment imagery here is complex: the disfiguring of the garment (<em>yitḥappēś lᵊḇûšî</em>) may refer to the skin disease that has made his outer covering unrecognizable. In the ancient world, clothing was identity — the royal robe, the priestly garment, the traveler's cloak, the mourner's sackcloth all communicated social status. Job's garment/skin that no longer fits properly but 'binds him about like a collar' captures the bodily imprisonment of severe illness: the very body has become a constraint rather than a vehicle of social participation.</p>",
    "19": "<p>'God has cast me into the mire, and I have become like dust and ashes.' The casting into mire (<em>yōrēnî laḥōmer</em>) reverses the creation narrative: in Gen 2:7, God formed man from the dust (<em>ʿāp̄ār</em>) and breathed life into him; here, God has cast the living man back into the primordial mud. The phrase 'dust and ashes' (<em>ʿāp̄ār wāʾēp̄er</em>) is both the material of creation (Gen 3:19: 'for dust you are and to dust you shall return') and the expression Abraham used for himself before God (Gen 18:27: 'I who am but dust and ashes'). Job is experiencing ontological reduction — he is being unmade back to the pre-creation state.</p>",
    "20": "<p>'I cry to you for help and you do not answer me; I stand, and you only look at me.' The formal elements of the lament petition are present: the cry for help (<em>ʾešawwaʿ</em>, the standard lament cry) and the absence of answer (<em>lōʾ taʿănênî</em>). In the Psalms, this experience of divine silence is the central crisis of the individual lament genre (Ps 22:2: 'I cry by day, but you do not answer'; Ps 88:9: 'I call to you every day, O LORD'). Job's complaint has moved from legal challenge (ch13) to raw lament (ch30). The image 'you only look at me' suggests divine observation without intervention — the surveillance without assistance that is the cruelest form of apparent divine indifference.</p>",
    "21": "<p>'You have turned cruel to me; with the might of your hand you persecute me.' The accusation that God has turned cruel (<em>neh̯epakˑtā lᵊʾakzār lî</em>) is one of the most theologically radical statements in the OT — Job directly accuses the divine of cruelty. The verb <em>hāp̄aḵ</em> (to turn, overturn) is used for the overthrow of Sodom (Gen 19:25) and for the divine reversal of curses to blessings (Deut 23:5). God has 'overturned' toward Job — what was formerly blessing has been inverted into persecution. In the ANE context, the petition that God has become the petitioner's enemy rather than advocate is found in Mesopotamian lament texts (the Poem of the Righteous Sufferer: 'My god has forsaken me... who will take pity on me?').</p>",
    "22": "<p>'You lift me up on the wind; you make me ride on it, and you toss me about in the storm.' The wind imagery is simultaneously literal (Job may be referencing the physical experience of his illness, perhaps convulsions or the violent sensations of fever) and cosmological: wind in the ancient world was the divine vehicle, both creative (Gen 1:2: the divine wind over the primordial waters) and destructive (Isa 17:13; Job 1:19: the wind that killed his children). God is now using this cosmic vehicle against Job — the same storm-wind that opened creation is now destroying Job.</p>",
    "23": "<p>'For I know that you will bring me to death and to the house appointed for all living.' The 'house appointed for all living' (<em>bêṯ môʿēḏ lᵊkol-ḥāy</em>) is Sheol — the underworld that is the universal human destination in ancient Israelite thought. The use of <em>môʿēḏ</em> (appointed time, meeting place — the same term used for the sacred assembly in Lev 23) to describe death is grimly ironic: the sacred assembly time that marked covenant life is the same word for the 'meeting' of death that ends all covenant participation. Job is resigned to death but wants vindication before it comes (cf. 14:13-17).</p>",
    "24": "<p>'Yet does not one in a heap of ruins stretch out his hand, and in his disaster cry for help?' The verse describes the conventional expectation of rescue: even a person in ruins reaches out for help. The custom of responding to the cry of the suffering was a recognized social obligation in the ancient Near East — the Hammurabi Code and the Israelite law both required response to those in distress. Job's complaint: he has cried for help (v.20) and received no response. The implicit accusation is that God is violating the very standards of social obligation that the covenant community upholds at the human level.</p>",
    "25": "<p>'Did I not weep for him whose day was hard? Was not my soul grieved for the needy?' Job recalls his own practice of weeping with those who suffer (<em>hălōʾ bāḵîṯî liqšēh-yôm</em>, did I not weep for the one whose day was hard?). This is the practice commanded in the prophets (Isa 58:6-7) and reflected in Proverbs' wisdom about compassion for the poor (Prov 14:21, 31; 17:5). Job's implicit challenge: if even humans are required to respond to the cry of the suffering with compassion and practical action, why is God not doing the same for Job? The rhetorical question holds divine behavior to the standard that human wisdom itself sets.</p>",
    "26": "<p>'But when I hoped for good, evil came, and when I waited for light, darkness came.' The reversal of expectation (<em>qiwwîṯî lᵊṭôḇ wayyāḇōʾ rāʿ</em>) is the fundamental structure of the lament: the hopes that defined the sufferer's prayers have been systematically denied. In the Psalms, this reversal of expectation is the trigger for the lament section: 'my eyes are weak with waiting for my God' (Ps 69:3). The light/darkness antithesis (hoped for light, darkness came) echoes the creation narrative's fundamental distinction (Gen 1:3-4) — what was separated at creation is now reasserting its confusion in Job's experience.</p>",
    "27": "<p>'My inward parts are in turmoil and never still; days of affliction come to meet me.' The physiological description of emotional disturbance — 'inward parts' (<em>məʿay</em>, bowels/intestines — the seat of compassion and emotion in the ancient Israelite body map) 'boiling' (<em>rātăḥû</em>) without rest — captures the somatic experience of severe anxiety and grief. In the ancient world, emotions were not primarily experienced as mental phenomena but as somatic events: grief was felt in the bowels, courage in the liver, anger in the nostrils (<em>ʾap̄</em>). Job's affliction is being described at the most visceral, somatic level.</p>",
    "28": "<p>'I go about darkened, but not by the sun; I stand up in the assembly and cry for help.' The darkening that is not from the sun (<em>qāḏartî bᵊlōʾ ḥammāh</em>) refers to the darkened skin of mourning (sackcloth, ashes, sunlessness of grief) or possibly the darkened skin of the disease described in ch2:7. The word for the assembly (<em>qāhāl</em>) is the term for the formal covenant assembly of Israel — Job is crying for help in the formal communal gathering that was the venue for judicial proceedings, communal prayer, and covenant renewal. His cry in the assembly would have been understood as a formal legal petition.</p>",
    "29": "<p>'I am a brother of jackals and a companion of ostriches.' Jackals (<em>tannîm</em>) and ostriches (<em>bənôṯ yaʿănāh</em>) were the animals of the desolate places — their habitat was the wilderness and ruin outside the settled world. In the prophets, jackals inhabiting a place is the sign of divine judgment: the jackal-song over ruined Babylon (Isa 13:22; Jer 51:37), the ostriches wailing over Samaria (Mic 1:8). Job has become a companion of these creatures of desolation: he belongs to the wilderness, not the settled community. The reversal from ch29 (where he sat in the gate with the elders) is total — from the most honored seat in the community to brotherhood with the desert's scavengers.</p>",
    "30": "<p>'My skin turns black and falls from me, and my bones burn with heat.' The physical symptoms described — blackening skin (<em>šāḥar ʿôrî mēʿālay</em>), skin falling off, bones burning (<em>ḥōrāḇ miṣṣāmāʾ</em>) — are consistent with severe systemic illness, possibly the skin disease described in ch2:7 in an advanced stage. In the ancient world, the visible body was the primary indicator of social status and divine relationship: the body that was blackening and falling apart was the visible evidence that its owner was rejected by God and by the community. Job's symptoms are not merely medical but theological: the body's deterioration is read as divine judgment by the surrounding culture, which is precisely what Job is contesting.</p>",
    "31": "<p>'My lyre is turned to mourning, and my pipe to the voice of those who weep.' The musical instruments — the lyre (<em>kinnôr</em>, the instrument David played, 1 Sam 16:23) and the pipe (<em>ʿûḡāḇ</em>, a wind instrument, perhaps a type of flute) — were the symbols of joy and celebration in the ancient world. The conversion of music to mourning echoes the lament genre's formal structure: the psalms of individual lament often move from praise-memory to current lament and back. Job's musical reversal anticipates the restoration passage where God 'will fill your mouth with laughter, and your lips with shouting; those who hate you will be clothed with shame, and the tent of the wicked will be no more' (8:21) — but here, in ch30, only the mourning side of the reversal is present.</p>"
  },
  "31": {
    "1": "<p>'I have made a covenant with my eyes; how then could I gaze at a virgin?' Chapter 31 is the ethical centerpiece of the entire book — the most comprehensive inventory of moral responsibility in the OT. The oath of purgation (<em>šəḇûʿaṯ bərāʾ</em>) was a recognized legal form in the ancient Near East: the accused could swear an elaborate self-imprecatory oath to establish innocence when no witnesses were available. The covenant with his eyes against gazing at a virgin is the first clause — the control of desire at the point of origin (the eyes), before it issues in action. In Matthew 5:27-28, Jesus builds on exactly this tradition: the problem of lust is not merely the physical act but the covetous gaze, which Job here claims to have covenanted against.</p>",
    "2": "<p>'What would be my portion from God above and my heritage from the Almighty on high?' The rhetorical question about divine retribution for violating the eye-covenant introduces the theological framework of the oath: Job appeals to divine retribution as the sanction for his oath. In ANE legal practice, oaths invoked divine powers as witnesses and enforcers — the perjurer would face the deity's punishment. The divine names <em>ʾĒl</em> and <em>šadday</em> (the Almighty) are the wisdom tradition's preferred names for the international deity who enforces moral order beyond Israel's covenant boundaries.</p>",
    "3": "<p>'Is not calamity for the unrighteous, and disaster for those who work iniquity?' Job states the retribution theology not as his own view but as the theological framework within which his oath operates: the assumption is that wrong-doing brings calamity. This is the very theology the friends have applied to Job — and Job here uses it as the framework for his oath, not to endorse it unconditionally but to demonstrate that even by that framework, his suffering is inexplicable given his moral record. The tension is deliberate: if the retribution principle is true (as Job is here assuming for the oath's logic), then his suffering proves a violation of the principle.</p>",
    "4": "<p>'Does he not see my ways and number all my steps?' The divine omniscience that serves as the oath's enforcement mechanism is here made explicit. In the ANE context, divine surveillance of all human action was a foundational religious assumption — the Mesopotamian sun-deity Shamash (god of justice) was believed to see all things; the Ugaritic divine assembly maintained cosmic order by observing all human action. Job appeals to this divine omniscience not as a threat but as the ground of his oath: he has nothing to hide from the God who numbers all steps (cf. Ps 139:3: 'you search out my path and my lying down and are acquainted with all my ways').</p>",
    "5": "<p>'If I have walked with falsehood and my foot has hastened to deceit.' The first formal oath clause. The conditional form (<em>ʾim</em>, if — followed by the self-curse in vv.7-8) is the standard ANE oath structure: 'if I have done X, then let Y happen to me.' The falsehood (<em>šāwəʾ</em>) and deceit (<em>mirmāh</em>) targeted here are the foundational social virtues of the honor culture — truth-speaking and straight-dealing in commerce and social relations. In the ancient marketplace and court, false dealing undermined the entire system of honor that social life depended on; Job swears he has not participated in this.</p>",
    "6": "<p>'Let me be weighed in a just balance, and let God know my integrity!' The image of the balance (<em>mōʾznayim</em> ṣedeq, just scales) is the standard icon of justice in the ancient Near East — the Egyptian weighing of the heart scene, Mesopotamian justice imagery, and Israelite law all use the scale as the instrument of fair assessment. Job's request that God weigh him in just scales is a dramatic reversal of his earlier complaint that his calamity is too heavy for scales (6:2-3: 'Oh that my vexation were weighed... it would be heavier than the sand of the sea'). Job is confident that a just divine assessment will vindicate him.</p>",
    "7": "<p>'If my step has turned aside from the way and my heart has gone after my eyes, and if any spot has clung to my hands.' The triple condition expands the oath: feet turning aside from the right path (moral direction), heart following the eyes (desire leading to action), and stain on the hands (the physical consequence of wrongdoing — the same 'handwashing' imagery of innocence in Deut 21:6-7 and Ps 26:6). In Israelite jurisprudence, the hands that did the act were literally implicated in the act's moral weight — ritual handwashing as innocence declaration and the 'blood on your hands' idiom reflect the somatic moral theory in which the body parts that commit the act bear the guilt.</p>",
    "8": "<p>'Then let me sow, and another eat, and let what grows for me be rooted out.' The self-curse of losing the harvest to another is drawn directly from the Deuteronomic covenant curse structure (Deut 28:30-31, 33: 'you shall plant a vineyard but shall not eat of it... a nation you have not known shall eat up your livestock and the fruit of your ground'). The loss of one's agricultural labor to another was the covenant curse for covenant violation. Job adopts this structure as the appropriate penalty for the moral violations he is denying — if he has done these things, let the covenant curses fall on him.</p>",
    "9": "<p>'If my heart has been enticed toward a woman, and I have lain in wait at my neighbor's door.' The adultery clause is the most socially and legally charged in the oath. In ancient Israelite law, adultery was a capital offense (Lev 20:10; Deut 22:22) and a violation of the neighbor's property rights (the wife was legally under the husband's authority). The phrase 'lying in wait at the neighbor's door' uses the vocabulary of the stalker and the ambusher — it is not a spontaneous act but a premeditated one, which increases the culpability. The wisdom literature's treatment of the adulteress's husband as a cuckolded victim (Prov 6:32-35: the jealous husband will show no mercy) reflects the severe social consequences of adultery for all parties.</p>",
    "10": "<p>'Then let my wife grind for another, and let others bow down over her.' The self-curse for adultery is the degradation of his own wife: forced labor (grinding grain was the work of slaves — Exod 11:5; Isa 47:2; Lam 5:13) and sexual violation by others. The talion principle (an eye for an eye) is applied to sexual sin: Job, who has (he swears) not violated his neighbor's wife, swears that if he has, his own wife may be violated. The harshness of this self-curse reflects the severity with which the ancient world treated sexual violations of household boundaries — the honor of the household was dependent on the sexual fidelity of all its members.</p>",
    "11": "<p>'For that would be a heinous crime; that would be an iniquity to be punished by the judges.' The term <em>zimmāh</em> (heinous crime, a crime considered especially vile — used for incest in Lev 18:17; 20:14, and for other sexual violations) identifies adultery as among the most serious categories of social violation. The involvement of judges (<em>pᵊlîlîm</em>, the judicial authorities who governed the city gate) confirms that this is a formally cognizable offense, not merely a private moral failure. In the ancient world, the court at the city gate had jurisdiction over crimes against the household and the community; adultery was among the offenses that came before these judges.</p>",
    "12": "<p>'For that would be a fire that consumes as far as Abaddon, and it would burn to the root all my increase.' The fire metaphor for adultery's destructive power uses <em>ʾăḇaddôn</em> (Abaddon, the place of destruction — a name for the underworld deeper than Sheol, used in Job 26:6; 28:22; Rev 9:11). Fire that burns down to Abaddon is the most comprehensive destruction imaginable: it consumes not just the present estate but reaches to the very depths of existence. In Proverbs, the adulterer's fire is similarly described as self-destructive (Prov 6:27-29: 'can a man carry fire next to his chest and his clothes not be burned?'). The root destruction (<em>šōrāšay tiśśārēš</em>) removes all future possibility — not just present prosperity but generational continuation.</p>",
    "13": "<p>'If I have rejected the cause of my manservant or my maidservant, when they brought a complaint against me.' The treatment of slaves is the unexpected center of Job's oath — unexpected because it was not legally required in the ancient world. In Israelite law and ANE law generally, slaves had limited legal standing: the master was not typically required to adjudicate the slave's complaint fairly or at all. The fact that Job swears he has heard the complaints of his slaves (<em>ʿeḇed</em> and <em>ʾāmāh</em>) reflects an ethical position that exceeds legal obligation. This anticipates the Torah's development of slave rights (Exod 21:1-11; Deut 15:12-18) and points forward to the NT's treatment of the slave-master relationship in Ephesians 6:9 and Philemon.</p>",
    "14": "<p>'What then shall I do when God rises up? When he makes inquiry, what shall I answer him?' The theological grounding of the slave-treatment oath is striking: Job treats his slaves fairly because of divine examination (<em>ṣāḏāh</em>), not legal requirement. The same divine omniscience that grounds the oath (v.4: God numbers all steps) requires fair treatment of slaves: if God is watching all human interactions, the slave's cause is as visible to God as the cause of the free citizen. This is the OT's most explicit statement of the theological basis for slave rights: divine justice does not recognize the social distinctions that human law enforces.</p>",
    "15": "<p>'Did not he who made me in the womb make him? And did not one God fashion us in the womb?' The common origin of master and slave in the divine creative act is the anthropological ground for their equal moral status before God. In the ancient world, the social hierarchy was assumed to be divinely ordained — the Babylonian creation myth Enuma Elish explicitly creates humanity to serve the gods and implicitly legitimates human hierarchy. Job's theological argument is the counter: the same God who fashioned Job (<em>ʿāśānî</em>) fashioned the slave (<em>yaʿăśēhû</em>). The common humanity created by a single God establishes a moral floor beneath which the powerful cannot push the powerless without violating the Creator's intent.</p>",
    "16": "<p>'If I have withheld anything that the poor desired, or have caused the eyes of the widow to fail.' The turn to the poor, widow, orphan, and stranger (vv.16-23) addresses the prophetic social ethics that ran through the entire OT tradition. The widow's failing eyes (<em>ʿênê ʾalmānāh ʾăkalleh</em>) is the image of the widow who waits and watches for help that does not come — her eyes 'failing' from the effort of looking and hoping. This image appears in the lament psalms (Ps 69:3: 'my eyes grow dim with waiting for my God') and in the Servant's ministry to the failing-eyed (Isa 42:7: 'to open the eyes that are blind'). Job swears he has not been the cause of that failure.</p>",
    "17": "<p>'Or have eaten my morsel alone, and the fatherless has not eaten of it.' The communal table as moral obligation is a fundamental ANE social institution. In the ancient world, the generous host who fed all comers was the ideal of the nobility — the great man's table was the community's safety net. The isolation of food ('eating my morsel alone') was a recognized sign of social failure in a culture where table fellowship defined social bonds. In contrast, the ideal man's table in Proverbs 9 and in the ANE wisdom tradition is open: wisdom's house provides food for all. Job swears his table has been the traditional open table of the hospitable great man.</p>",
    "18": "<p>'For from my youth the fatherless grew up with me as with a father, and from my mother's womb I led the widow.' The claim that Job cared for the orphan from his youth is one of the book's most remarkable assertions: it defines Job's character as consistently oriented toward the vulnerable from the very beginning of his adult life. In the ancient world, the care of orphans and widows was the mark of the righteous king — the Hammurabi Code opens with Hammurabi's claim to care for the widow and orphan; the Ugaritic Aqhat epic praises the father Dan-el for judging the widow's cause. Job claims this royal-patron virtue as his personal characteristic from childhood.</p>",
    "19": "<p>'If I have seen anyone perish for lack of clothing, or the needy without covering.' The obligation to clothe the naked is closely related to the food obligation in ANE social ethics. The prophets identify clothing the naked as a mark of true worship alongside feeding the hungry (Isa 58:7: 'when you see the naked, to cover him'). In the covenant lawsuit section of Isaiah 1, the failure to care for the orphan and widow is the primary evidence of covenant violation. Job's oath that he has never seen the naked without clothing them implicitly appeals to the same prophetic standard.</p>",
    "20": "<p>'And his body has not blessed me, and he was not warmed with the fleece of my sheep.' The blessing of the body (<em>mᵊtānāyw bērăḵûnî</em>) — literally 'his loins blessed me' — is the physical expression of gratitude from the one who has been clothed: warmth experienced in the body is the evidence that the charitable act has been real and effective. Job's insistence on this somatic evidence is consistent with the ancient body-map in which social action was experienced physically. The 'fleece of my sheep' grounds the charitable act in Job's pastoral economy — the same flocks that made him wealthy have clothed the poor.</p>",
    "21": "<p>'If I have raised my hand against the orphan, because I saw my help in the gate.' The raising of the hand against the orphan (<em>ʾip̄ṯoh yāḏî ʿal-yāṯôm</em>) in the gate context is the legal image: the gate was the site of judicial proceedings, and raising a hand against the orphan meant using one's legal influence to oppress the powerless in the legal system. Job's specific temptation would have been to use his powerful gate-position (29:7-10: the princes and elders deferred to him at the gate) to oppress those who had no legal advocate. The phrase 'because I saw my help in the gate' acknowledges the temptation: when you are powerful in the legal system, oppressing the powerless is easy and goes unpunished.</p>",
    "22": "<p>'Then let my shoulder blade fall from my shoulder, and let my arm be broken from its socket.' The anatomical self-curse (shoulder blade from shoulder, arm from socket) uses the imagery of violent injury — these are wounds sustained in military combat or serious accidents. The hands and arms that would have oppressed the orphan are the specific body parts that would bear the punishment. In ANE legal tradition, the talion principle was applied to the offending body part: the hand that struck was cut off (Hammurabi Code §195); the eye that transgressed was put out. Job's self-curse adopts this talion logic — if his arm has oppressed, let his arm be destroyed.</p>",
    "23": "<p>'For I was in terror of calamity from God, and I could not have faced his majesty.' The explicit motivation for Job's ethical behavior — terror of divine judgment and inability to face divine majesty (<em>śeʾēṯô</em>, his rising/majesty) — grounds the entire oath in theological fear rather than social convention or legal obligation. This is significant: Job's ethics are not primarily cultural conformism but theological response to divine omniscience. The same divine majesty that the friends invoke as the ground of their theology (and that Job challenges in the legal speeches) is here acknowledged as the motivating force behind Job's ethical life. Job's theology is not inconsistent — he fears divine judgment precisely because he takes it seriously.</p>",
    "24": "<p>'If I have made gold my trust or called fine gold my confidence.' The wealth oath (vv.24-25) addresses the temptation of prosperity — specifically the temptation to trust in wealth rather than in God. In the wisdom literature, the danger of riches is well-documented (Prov 11:28: 'whoever trusts in his riches will fall'; Prov 23:4-5). The specific contrast between trusting in gold (<em>zāhāḇ... kāṯem</em>) and trusting in God is the prophetic critique of idolatry — in the prophets, wealth becomes a functional idol when it replaces divine dependence (Isa 2:7-8; Ezek 7:19: 'their gold and silver cannot deliver them in the day of wrath').</p>",
    "25": "<p>'If I have rejoiced because my wealth was abundant or because my hand had found much.' The joy in wealth (<em>ʾeśmaḥ kî-rāḇ ḥêlî</em>) is what the Deuteronomic tradition warns against: 'beware lest you say in your heart, \"My power and the might of my hand have gotten me this wealth\"' (Deut 8:17). Job's oath that he has not rejoiced in wealth as wealth — but has held it as a trust from God — is the rejection of what the prosperity gospel would call blessing but what the wisdom tradition calls a snare. The hand that 'found much' (<em>māṣāʾ yāḏî rāḇ</em>) is the attribution of wealth to human agency that the Deuteronomic tradition identifies as spiritual danger.</p>",
    "26": "<p>'If I have looked at the sun when it shone, or the moon moving in splendor.' The astral worship oath addresses a temptation that was particularly acute in the ancient world. The worship of the sun and moon was the dominant form of religious practice in Mesopotamia (Shamash the sun, Sin the moon) and was a recognized temptation for Israelites (Deut 4:19; 17:3; 2 Kgs 23:5, 11; Jer 8:2; Ezek 8:16). The magnificence of the sun and moon — their undeniable visual splendor — made them natural objects of religious awe. Job's oath that he has not responded to this splendor with religious devotion is a claim to monotheistic fidelity in an environment where astral worship was everywhere.</p>",
    "27": "<p>'And my heart has been secretly enticed, and my mouth has kissed my hand.' The specific gesture of the kiss of the hand toward the heavenly body was the standard act of astral worship in the ancient world — documented in Mesopotamian, Egyptian, and Canaanite religious practice. The secrecy (<em>bassēṯer</em>) is important: public astral worship was legally prohibited in Israel (Deut 17:3-7), so the private act of hand-kissing toward the sun or moon was the clandestine form of the temptation. Job's oath covers not just public idolatry but private religious heart-devotion — he has not even secretly kissed his hand toward the heavenly bodies.</p>",
    "28": "<p>'This also would be an iniquity to be punished by the judges, for I would have been false to God above.' The classification of astral worship as an iniquity requiring judicial punishment (<em>ʿāwōn pᵊlîlî</em>) is directly drawn from Deuteronomic law (Deut 17:12: the case of astral worship goes to the judges, and the penalty is death). Job's oath addresses the most serious category of Israelite religious offense — the worship of other deities — and swears that he has not committed it even in the secret of his heart. The grounding 'I would have been false to God above' (<em>ḵiḥaštî lāʾēl mimaʿal</em>) identifies the theological offense beneath the legal one: astral worship is lying to God.</p>",
    "29": "<p>'If I have rejoiced at the ruin of him who hated me, or exulted when evil overtook him.' The enemy-joy oath (vv.29-30) addresses what Proverbs calls <em>šāmaḥ bᵊmappleṯ śōnəʾeḵā</em> (rejoicing in the fall of your enemy, Prov 24:17-18) — a recognized temptation that the wisdom tradition explicitly prohibits. In the honor-shame culture, the defeat of an enemy was naturally cause for satisfaction: it vindicated one's honor and demonstrated the enemy's wrong. But the wisdom tradition's prohibition reflects a deeper anthropological awareness that gloating over another person's calamity, even an enemy's, violates the common humanity that dignity requires. Job swears he has not done this.</p>",
    "30": "<p>'I have not let my mouth sin by asking for his life with a curse.' The curse against the enemy (<em>lᵊʾallēl bᵊnap̄šô</em>, to curse his life/soul) was a recognized legal and religious act in the ancient world — formal curses were believed to be effective, and calling down divine judgment on an enemy was both a common desire and a recognized religious act. In the Psalms, the imprecatory psalms (Ps 69, 109, 137) express exactly this desire. Job swears he has not even given voice to the desire for his enemy's death — he has not prayed against them. This exceeds even the wisdom tradition's command not to rejoice at the enemy's fall; Job has not even allowed his mouth to formalize the inner desire for the enemy's destruction.</p>",
    "31": "<p>'If the men of my tent have not said, \"Who is there that has not been filled with his meat?\"' The hospitality clause recalls the social obligation of the great man's table. In the ancient world, the great household (<em>ʾohel</em>, tent — a patriarchal term for the clan household) was expected to be generous to all who came. The rhetorical question 'who has not been filled with his meat?' asked by the 'men of his tent' (his household and community members) is the characteristic praise of the hospitable host: everyone testifies that no one has gone away unfed. Job's claim is that his household was known for this — the universal positive testimony of the community members is the evidence.</p>",
    "32": "<p>'The stranger has not lodged in the street; I have opened my doors to the traveler.' The obligation to house strangers (<em>gēr</em>, the resident alien or the traveling stranger) was one of the most emphasized social obligations in Israelite law (Lev 19:33-34; Deut 10:18-19; 14:29; 24:17-22). The theological grounding was the Exodus: 'you shall not wrong a stranger or oppress him, for you were strangers in the land of Egypt' (Exod 22:21). In the wider ANE context, hospitality was the sacred obligation of all civilized people — the gods themselves were believed to travel in disguise and to reward or punish the hospitable and inhospitable (reflected in Gen 18 and in the Greek tradition of Zeus Xenios, the god of hospitality). Job's open door to the traveler fulfills both social and theological obligation.</p>",
    "33": "<p>'If I have concealed my transgressions as others do by hiding my iniquity in my heart.' The concealment of sin (<em>ḵissîṯî kᵊʾāḏām pᵊšāʿāy</em>) is contrasted with the open disclosure that Job's oath represents. The phrase 'as others do' (<em>kᵊʾāḏām</em>, like Adam, or like humankind) may specifically allude to Adam's hiding in the garden after the fall (Gen 3:8-10: Adam hid himself from the face of YHWH) or may use 'Adam' as a generic reference to human concealment. Job's oath is itself the anti-concealment: by making these formal declarations in front of witnesses, he is bringing his entire moral record into public view rather than hiding it. The open oath is the formal opposite of Adam's hiding.</p>",
    "34": "<p>'Because I stood in great fear of the multitude, and the contempt of families terrified me, so that I kept silence and did not go out of doors.' The social fear that could prevent honest speech — fear of the crowd (<em>hāmôn</em>) and family contempt (<em>bûz mišpāḥôṯ</em>) — is the social pressure that the honor-shame culture exerts against honest disclosure. Job is claiming that he was not silenced by social fear: he did not suppress the truth to protect his reputation before the crowd. This is significant: in the honor-shame world, social pressure was the most powerful force constraining behavior. Job's oath claims independence from this pressure in both his ethical behavior and his willingness to make this public declaration.</p>",
    "35": "<p>'Oh, that I had one to hear me! Here is my signature! Let the Almighty answer me! Oh, that I had the indictment written by my adversary!' The climax of the oath — the <em>tāw</em> (last letter of the alphabet, the signature mark — <em>tāwî</em>) is Job's formal signature on the oath-document. In ancient legal culture, the completion of a legal document was marked by the signatory's seal or signature. Job signs the oath with the final letter of the alphabet — a complete signature — and demands a written indictment (<em>sēp̄er</em>, scroll/document) from his adversary (God, treated as the opposing party in the lawsuit). The demand for a written indictment is the formal legal move that requires the opposing party to specify their charges in writing — the most specific and committed form of accusation.</p>",
    "36": "<p>'Surely I would carry it on my shoulder; I would bind it on me as a crown.' The image of wearing the adversary's indictment as a crown rather than hiding from it is an extraordinary reversal of the shame/honor dynamic. In the ancient world, an indictment was carried as a sign of shame — the accused bore the document of their accusation publicly. Job's claim that he would wear it as a crown (<em>ʿăṭārāh</em>, the royal or victory crown) transforms the legal document of shame into a badge of honor: the indictment's content would, if read, demonstrate his innocence and thereby function as a crown of vindication. The bravado of the image reflects Job's total confidence in his case.</p>",
    "37": "<p>'I would give him an account of all my steps; like a prince I would approach him.' The 'account of all my steps' (<em>mispār ṣəʿādāy ʾaggîḏennû</em>) is the formal accounting that the divine book would require — every step documented and explained. Job would approach this accounting 'like a prince' (<em>kᵊmô-nāgîd</em>) — with the dignity and confidence of a nobleman, not the cowering of the guilty. The word <em>nāgîd</em> (prince, leader, designated leader) is used for the king-designate and for military commanders — it implies the bearing of someone who knows their position and their right. Job's confidence in approaching the divine accounting is the culmination of the entire oath: he has nothing to hide because he has done nothing to hide.</p>",
    "38": "<p>'If my land has cried out against me and its furrows have wept together.' The land-testimony oath (vv.38-40) shifts from social ethics to agricultural ethics — specifically, the obligations of the landowner to the land and to those who work it. In the OT, the land itself was understood to be a moral witness: it could cry out against the blood shed on it (Gen 4:10: Abel's blood crying from the ground), and it vomited out the inhabitants who defiled it with sexual sin (Lev 18:25, 28). The covenant between the Israelite people and the land was moral — the land's productivity depended on the people's faithfulness.</p>",
    "39": "<p>'If I have eaten its yield without payment and made its owners breathe their last.' The specific violation addressed here — eating the land's yield without payment and causing the owners to die — refers to land theft by causing the rightful owners to die. This connects to the Naboth's vineyard narrative (1 Kgs 21): Ahab and Jezebel's seizure of Naboth's vineyard through false accusation and judicial murder is the paradigmatic case of this violation. Job swears he has not engaged in this form of social violence — using economic or judicial power to dispossess legitimate landowners. The prophets repeatedly condemn this violation (Isa 5:8: 'woe to those who join house to house, who add field to field').</p>",
    "40": "<p>'Let thorns grow instead of wheat, and foul weeds instead of barley.' The covenant curse of agricultural reversal — thorns and weeds replacing wheat and barley — is drawn directly from the Deuteronomic curse structure (Deut 28:38-42: crop failures as covenant punishments) and echoes the fall narrative (Gen 3:17-18: 'cursed is the ground because of you; thorns and thistles it shall bring forth for you'). The specific reversal of the cultivated crops (wheat, barley) into the uncultivated wilderness plants (thorns, weeds) represents the un-creation of agriculture — the reversal of the human calling to cultivate the earth. Job accepts this most agricultural of curses as the appropriate consequence of agricultural injustice.</p>"
  },
  "32": {
    "1": "<p>'So these three men ceased to answer Job, because he was righteous in his own eyes.' The notice that the three friends 'ceased to answer' (<em>wayyišbᵊṯû</em>, came to rest, stopped) because Job was 'righteous in his own eyes' (<em>ṣaddîq bᵊʿênāyw</em>) signals the exhaustion of the conventional wisdom dialogue. Job's claim to innocence (<em>ṣaddîq</em>) in his own sight is not simply pride — it is the forensic assertion of the oath in ch31. The friends have been unable to answer, not because they are convinced but because they have run out of arguments. The stage is now set for a new voice.</p>",
    "2": "<p>'Then Elihu the son of Barachel the Buzite, of the family of Ram, burned with anger.' The introduction of Elihu is unique in the dialogue: he is given a complete genealogy (<em>ben-Baraḵʾēl habbûzî mimmišpaḥat Rām</em>), unlike the three friends who were simply identified by their cities (Eliphaz the Temanite, Bildad the Shuhite, Zophar the Naamathite). The Buzite identification connects Elihu to the region near Teman — Buz appears in Gen 22:21 as a son of Nahor (Abraham's brother), placing Elihu in the broader Aramaean/patriarchal genealogical world. The complete genealogy signals that Elihu is a real person, not a type, and that his authority claim is grounded in legitimate lineage.</p>",
    "3": "<p>'He burned with anger also at Job's three friends because they had found no answer, although they had declared Job to be in the wrong.' Elihu's anger at the three friends has a different basis from his anger at Job: the friends have condemned Job without being able to refute his arguments. In the ANE disputation context, this was the worst possible outcome — declaring the opponent wrong without being able to demonstrate it was intellectual dishonesty dressed as theological authority. Elihu's critique anticipates YHWH's verdict (42:7: 'you have not spoken of me what is right, as my servant Job has') — the friends' conclusion was wrong, and their reasoning was insufficient.</p>",
    "4": "<p>'Now Elihu had waited to speak to Job because they were older than he.' The social protocol of deference to elders (<em>ḥikˑkāh ʾeṯ-ʾiyyôḇ biddᵊḇārîm kî zᵊqenîm hēmmāh mimmennû</em>) is the specific cultural context for Elihu's delayed entry into the dialogue. In the ANE wisdom tradition, the young were expected to listen while the elders spoke — the entire wisdom educational system was built on the transmission of knowledge from elder to younger. Sir 32:7-9 reflects this same protocol in the Second Temple period: 'speak, young man, only if necessary, and only twice, and then only when pressed; give a brief answer... do not interrupt.' Elihu's waiting is culturally appropriate; his eventual speaking requires justification.</p>",
    "5": "<p>'And when Elihu saw that there was no answer in the mouth of the three men, he burned with anger.' The trigger for Elihu's entry is the exhaustion of the elder disputants: the protocol of deference can be set aside when the elders have demonstrably failed. In the wisdom tradition, the failure of the elders to provide adequate counsel was the recognized occasion for a junior to speak (the Ahiqar tradition, popular throughout the ANE, features a young man whose wisdom surpasses that of the established sages). Elihu's anger is presented as righteous indignation at the theological failure of those who should have answered Job adequately.</p>",
    "6": "<p>'And Elihu the son of Barachel the Buzite answered and said: I am young in years, and you are aged; therefore I was timid and afraid to declare my opinion to you.' Elihu's opening self-identification as young (<em>ṣāʿîr leyāmîm</em>, young in years) and his explicit acknowledgment of timidity (<em>zaḥaltî waʾîrāʾ</em>, I was timid and afraid) before the aged (<em>yīšišîm</em>, the elders) demonstrates that he understands and has been observing the protocol. His deference is not mere politeness but genuine cultural formation in the wisdom tradition. The contrast with the three friends is pointed: they spoke with confident authority; Elihu speaks with acknowledged limitation but ultimately more theological insight.</p>",
    "7": "<p>'I said, \"Let days speak, and many years teach wisdom.\"' The proverbial wisdom that days (<em>yāmîm</em>, years of experience) and many years (<em>rōḇ šānîm</em>) teach wisdom (<em>ḥokmāh</em>) is the standard defense of the elder-authority system. This is the same tradition that Job mockingly cited in 12:12 ('wisdom is with the aged') — but Elihu cites it as a sincere belief that he has actually followed by waiting for the elders to exhaust their speeches. The difference between Elihu and Job is that Elihu has genuinely subordinated himself to the social protocol; Job's citation in ch12 was sarcastic dismissal of the friends' false claim to wisdom.</p>",
    "8": "<p>'But it is the spirit in man, the breath of the Almighty, that makes him understand.' The theological justification for Elihu's speaking despite his youth appeals to the divine spirit (<em>rûaḥ... wənišmaṯ šadday</em>, the spirit... and the breath of the Almighty) as the source of understanding. This is the same spirit that animated the human being at creation (Gen 2:7: <em>nišmaṯ ḥayyîm</em>, the breath of life). Elihu's argument is pneumatological: the spirit of God, not the accumulation of years, is the ultimate source of wisdom. This theological move positions him to speak without the accumulated years — if the spirit has given understanding, age is a secondary qualification, not a primary one.</p>",
    "9": "<p>'It is not the old who are wise, nor the elders who understand what is right.' The explicit challenge to elder-authority is a remarkable social move in the ANE context. Elihu is directly contradicting the foundational assumption of the wisdom educational system: that age is equivalent to wisdom. In the Israelite prophetic tradition, there was a recognized tension between the wisdom of the elders and the charismatic authority of the spirit-inspired prophet (cf. the young Jeremiah's claim against the established temple authorities). Elihu's position combines the wisdom tradition's pneumatological claim with the prophetic tradition's challenge to institutional authority.</p>",
    "10": "<p>'Therefore I say, \"Listen to me; let me also declare my opinion.\"' The formal claim to speak (<em>šimᵊʿû-lî ʾăḥawweh daʿ-ʾap̄ gam-ʾānî</em>) mirrors Job's own demand for a hearing in ch13. The wisdom disputation's formal protocol required each speaker to establish their right to speak before making their argument. Elihu's establishment of the right to speak (despite his youth) through the theological argument of vv.8-9 positions him as a legitimate new voice in the dialogue — one who has waited respectfully but now speaks by divine authorization.</p>",
    "11": "<p>'Behold, I waited for your words, I listened for your wise sayings, while you searched out what to say.' The description of waiting (<em>ḥikˑkîṯî ʾet-ḏiḇrêkem</em>) and careful listening for wise sayings (<em>ṯûšiyyōṯêkem</em>, your wise practical maxims — the same <em>tûšiyyāh</em> term used in 12:16 for divine wisdom) while they 'searched out what to say' frames the three friends' speeches as effortful searches rather than fluent wisdom. The image of searching for words implies difficulty — the best they could manage required effort. In the oral culture's standards for wisdom speech, the truly wise man spoke with ease because wisdom was already in him; the effortful speech betrayed its inadequacy.</p>",
    "12": "<p>'I gave you my full attention, and behold, there was none among you who refuted Job or who answered his words.' The devastating verdict: after all the speeches, not one of the three friends has successfully refuted (<em>môkîaḥ</em>, one who reproves/refutes) Job. <em>Môkîaḥ</em> is the technical term for the one who successfully demonstrates the opponent's error in the disputation — Eliphaz had promised this role (22:4) but failed to deliver it. Elihu's assessment is that the entire dialogue has been a failure of refutation: the friends talked extensively but did not answer the substance of Job's case.</p>",
    "13": "<p>'Beware of saying, \"We have found wisdom; God may vanquish him, not a man.\"' Elihu warns against the friends' temptation to claim that they have found wisdom while conceding that only God can actually answer Job. This is the intellectual dishonesty of the position: to declare that Job is in the wrong but then retreat to 'God will have to deal with him' is to admit that human argument has failed. In the honor context of the wisdom disputation, this retreat would be a face-saving maneuver that preserves the claim to wisdom while avoiding the actual task of answering. Elihu refuses this maneuver and positions himself as the one who will actually answer Job on the human plane before the divine answer comes.</p>",
    "14": "<p>'He has not directed his words against me, and I will not answer him with your speeches.' Elihu's declaration of methodological independence is significant: Job's words have not been directed against Elihu personally, so he has no personal stake in refuting them — he can approach the matter without the defensiveness of the three friends, who had been personally challenged by Job's accusations. Furthermore, he will not use their speeches (<em>bᵊmillekem</em>): he is not simply repeating their arguments but bringing something new. The methodological novelty is the basis for Elihu's claim to speak — he has a different approach, not merely a rehearsal of the failed arguments.</p>",
    "15": "<p>'They are dismayed; they answer no more; they have not a word to say.' The description of the three friends as dismayed (<em>ḥaṯˑtû</em>, terrified, shattered — the same root as <em>ḥittāh</em>, the terror that the friends warned would fall on Job if he continued his challenge in 13:11) is ironic: the terror they predicted for Job has actually fallen on them. They 'answer no more' — their speechlessness is the formal proof of their defeat in the disputation. In the ancient oral culture, the loss of speech was the loss of the argument; the man who cannot speak has conceded the contest.</p>",
    "16": "<p>'And shall I wait, because they do not speak, because they stand there, and answer no more?' The rhetorical question formally justifies Elihu's breaking of the waiting protocol: since the elders have fallen silent (<em>ʿāmᵊdû lōʾ-ʿānû-ʿôḏ hēʾādîqû mimmennî millîm</em>, they stood there and answered no more), the social reason for his silence no longer exists. The waiting was for the elders to exhaust their speeches; that exhaustion has now occurred. The protocol's conditions having been met, Elihu is now legitimately free to speak without violating the social order — his speech is not an interruption but a succession.</p>",
    "17": "<p>'I also will answer with my share; I also will declare my opinion.' The phrase 'my share' (<em>ḥelqî</em>, my portion, my assigned part) treats the disputation as a communal endeavor in which each participant has an assigned share. In the wisdom education context, the dialogue had specific roles: the master asked, the student answered, and the disputation proceeded in assigned turns. Elihu's 'share' is the contribution of the participant who has been waiting his turn. The word <em>daʿat</em> (opinion, knowledge, understanding) is the same vocabulary as the divine wisdom that Elihu claimed in v.8 — he will speak from that divinely-given understanding.</p>",
    "18": "<p>'For I am full of words; the spirit within me constrains me.' The fullness of words (<em>mālēʾṯî millîm</em>) and the constraining spirit (<em>rûaḥ biṭˑnî yᵊṣêqannî</em>) describe the prophetic experience of compelled speech — the inability not to speak when the divine word is pressing for expression. This language resonates with the prophetic tradition: Jeremiah's 'there is in my heart as it were a burning fire shut up in my bones, and I am weary with holding it in, and I cannot' (Jer 20:9); Amos's 'the lion has roared; who will not fear? The Lord God has spoken; who can but prophesy?' (Amos 3:8). Elihu's speech is presented as quasi-prophetic compulsion, not merely intellectual confidence.</p>",
    "19": "<p>'Behold, my belly is like wine that has no vent; like new wineskins ready to burst.' The wine-in-a-sealed-vessel image is familiar from the NT (Matt 9:17: new wine in old wineskins). In the ancient world, wine that was sealed in a new skin before fermentation was complete would build pressure and burst the skin if not vented. The image captures the physiological pressure of unspoken words in a culture where speech was the primary medium of social existence: the person who must speak but cannot is experiencing genuine somatic distress. The new wine/new wineskin image also suggests that Elihu's contribution will be genuinely new, not merely a recycling of the old arguments.</p>",
    "20": "<p>'I must speak, that I may find relief; I must open my lips and answer.' The necessity of speech (<em>ʾăḏabbᵊrāh wəyirwah-lî</em>, I must speak that I may find relief/breathing-room) is physiological: the constriction of the unexpressed word creates physical distress. This is the ancient world's somatic understanding of emotional and intellectual pressure — the body's experience of the unexpressed is real discomfort. The 'relief' sought is not emotional catharsis in the modern sense but the physical relief of pressure that builds when the mouth is constrained from its natural function.</p>",
    "21": "<p>'I will not show partiality to any man or use flattery toward any person.' Elihu's formal disclaimer of partiality (<em>ʾiśśāʾ-nāʾ p̄ənê-ʾîš</em>, lifting up the face of a man) and flattery (<em>ʾăḵanneh lᵊʾāḏām</em>, giving someone a flattering title) echoes the judicial standard of impartiality that Job appealed to in 13:8-10 against the friends (who showed partiality toward God in the disputation by refusing to evaluate the arguments fairly). Elihu positions himself as the honest evaluator that the friends failed to be: he will evaluate both Job's and God's positions impartially, without the social deference that corrupted the friends' arguments.</p>",
    "22": "<p>'For I do not know how to flatter, for then my Maker would soon take me away.' The grounding of non-flattery in the fear of the Maker (<em>ʿōśenî</em>, the one who made me) continues Elihu's theological self-positioning: he speaks truthfully because the God who made him will judge him for flattery. This is the same divine accountability that grounded Job's oath in 31:14, 23 — the fear of divine examination as the motivation for honest dealing. Elihu's final self-presentation positions him as a man of divine accountability parallel to Job, but with the claim that his accountability produces a different conclusion about Job's case.</p>"
  }
}

def main():
    d = load_comm('mkt-context', 'job')
    before = sum(len(v) for v in d.values())
    merge_comm(d, JOB_CONTEXT_30_32)
    after = sum(len(v) for v in d.values())
    save_comm('mkt-context', 'job', d)
    for ch in ['30', '31', '32']:
        vs = sorted(d.get(ch, {}).keys(), key=int)
        print(f'  ch{ch}: {len(vs)} verses')
    print(f'wrote {after - before} new verses ({after} total)')

if __name__ == '__main__':
    main()
